// Merge privacy translations into main translations
Object.assign(translations.en, privacyTranslations.en);
Object.assign(translations.es, privacyTranslations.es);

document.addEventListener('DOMContentLoaded', () => {
    const langBtns = document.querySelectorAll('.lang-btn');
    const storedLang = localStorage.getItem('site_lang') || 'en';

    setLanguage(storedLang);

    langBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            const lang = btn.getAttribute('data-lang');
            setLanguage(lang);
        });
    });
});

function setLanguage(lang) {
    // Update active button state
    document.querySelectorAll('.lang-btn').forEach(btn => {
        btn.classList.toggle('active', btn.getAttribute('data-lang') === lang);
    });

    // Save preference
    localStorage.setItem('site_lang', lang);

    // Update text
    const elements = document.querySelectorAll('[data-i18n]');
    elements.forEach(el => {
        const key = el.getAttribute('data-i18n');
        // Handle optional keys or fallback
        if (translations[lang] && translations[lang][key]) {
            el.innerHTML = translations[lang][key];
        } else if (privacyTranslations.en[key]) {
            // Fallback to English if ES translation missing during WIP
            el.innerHTML = privacyTranslations.en[key];
        }
    });

    // Update html lang attribute
    document.documentElement.lang = lang;
}
